    function bindPanelWheelScroll(panel) {
        const content = panel.querySelector('.xxt-content');
        if (!content) return;

        panel.addEventListener('wheel', function (e) {
            const target = e.target;
            const tag = target && target.tagName ? target.tagName.toUpperCase() : '';

            if (['INPUT', 'SELECT', 'TEXTAREA'].includes(tag)) {
                return;
            }

            if (!content.contains(target)) return;
            e.preventDefault();
            e.stopPropagation();
            content.scrollTop += e.deltaY;
        }, { passive: false });
    }

    function setActiveUiPage(pageName) {
        const panel = document.getElementById(PANEL_ID);
        if (!panel) return;

        panel.querySelectorAll('.xxt-nav-btn').forEach(btn => {
            btn.classList.toggle('active', btn.getAttribute('data-page') === pageName);
        });

        panel.querySelectorAll('.xxt-page').forEach(page => {
            page.classList.toggle('active', page.getAttribute('data-page') === pageName);
        });
    }

