    function manualRefreshStatus() {
        xxtLog('info', '执行单次状态检测。', {}, { minGap: 800 });
        uiLiveRefreshUntil = Date.now() + 2500;
        frameReportMap.clear();
        reportTopLocal();
        broadcast('scan');
        uiLastSnapshot = buildUiSnapshot();
        uiLastSnapshotAt = Date.now();
        updatePanelStatus('已执行一次状态检测，正在等待 iframe 回传补充信息。', true);

        setTimeout(() => {
            uiLastSnapshot = buildUiSnapshot();
            uiLastSnapshotAt = Date.now();
            updatePanelStatus('单次检测完成：状态区已更新。', true);
        }, 1200);
    }

    function manualEvaluateFlow() {
        if (!config.autoNext) {
            reportTopLocal();
            updatePanelStatus('自动下一节未开启：仅刷新状态，不执行下一节判断');
            return;
        }

        evaluateAutoNext();
        setTimeout(() => updatePanelStatus('已手动执行一次自动下一节判断'), 300);
    }

    function manualBookScrollOnce() {
        const taskInfo = getTaskPointInfo();

        if (!config.bookAutoScroll) {
            config.bookAutoScroll = true;
            bookScrollRunning = true;
            saveConfig();
            updateBookScrollButton();
        }

        if (!hasBookReadableStructureInAccessibleWindows(taskInfo)) {
            updatePanelStatus('当前未检测到图书任务 / #Readweb / Jimg，已阻止图书滚动');
            return;
        }

        armBookScrollEverywhere(900);

        setTimeout(() => {
            const moved = doBookAutoScroll(taskInfo);
            updatePanelStatus(moved ? '已执行一次图书轻滚' : '已触发图书轻滚，但当前滚动目标未移动');
        }, 80);
    }

    function manualStopBookScroll() {
        stopBookScrollEverywhere();
        updatePanelStatus('已手动停止图书滚动授权和定时器');
    }

    function manualTriggerSpecialTextVideo() {
        const handled = handleSpecialTextVideoFlow();

        if (!handled) {
            updatePanelStatus('未检测到 span.special-text，未触发特殊视频流程');
        }
    }

    function manualTaskPointDebug() {
        const taskInfo = getTaskPointInfo();
        const bookMarker = getBookAreaJobMarkerInfo();
        const special = findSpecialTextTag();
        const bookContext = isCurrentBookContext(taskInfo);
        const learningTarget = findLearningTargetPage();
        const taskCondition = findTaskConditionTag();

        updatePanelStatus(
            `任务点检测｜job:${taskInfo.hasJobIcon ? '有' : '无'}｜完成<i>:${taskInfo.hasFinishedIcon ? '是' : '否'}｜task-condition:${taskCondition ? '有' : '无'}｜图书:${bookContext ? '是' : '否'}｜图书标记:${bookMarker.count}｜图书完成:${bookMarker.hasBookFinishedIcon ? '是' : '否'}｜学习目标:${learningTarget ? '有' : '无'}｜special:${special ? '有' : '无'}`
        );
    }

